  // Helper function to format integer part with Indian numbering
  // Numbers < 10000: no commas (e.g., 1000, 9999)
  // Numbers >= 10000: Indian numbering (e.g., 10,000, 1,00,000)
  String _formatIntegerWithIndianNumbering(String integerPart) {
    if (integerPart.length <= 3) {
      // No commas for numbers less than 1000
      return integerPart;
    } else {
      // Indian numbering for numbers >= 1000
      // First 3 digits from right have no comma, then every 2 digits get a comma
      final length = integerPart.length;
      final lastThreeDigits = integerPart.substring(length - 3);
      final remainingDigits = integerPart.substring(0, length - 3);

      // Format remaining digits with Indian numbering (comma every 2 digits)
      String formattedRemaining = '';
      int count = 0;
      for (int i = remainingDigits.length - 1; i >= 0; i--) {
        if (count > 0 && count % 2 == 0 && i >= 0) {
          formattedRemaining = ',' + formattedRemaining;
        }
        formattedRemaining = remainingDigits[i] + formattedRemaining;
        count++;
      }

      // Combine: remaining digits (with commas) + last 3 digits (no comma)
      return formattedRemaining.isEmpty
          ? lastThreeDigits
          : '$formattedRemaining,$lastThreeDigits';
    }
  }

  // Helper function to format amount: append .00 if no decimals and add Indian number formatting
  String _formatAmount(String value, {int decimalPlaces = 2}) {
    if (value.trim().isEmpty) {
      return '';
    }

    // Remove any currency symbols, spaces, and commas
    String cleaned = value
        .trim()
        .replaceAll('₹', '')
        .replaceAll(' ', '')
        .replaceAll(',', '');

    String integerPart;
    String decimalPart = '';
    bool hasDecimal = false;

    // Check if it contains a decimal point
    if (cleaned.contains('.')) {
      final parts = cleaned.split('.');
      integerPart = parts[0].isEmpty ? '0' : parts[0];
      decimalPart = parts.length > 1 ? parts[1] : '';

      // Check if decimal part has any non-zero value
      final hasNonZeroDecimal = decimalPart.isNotEmpty &&
          decimalPart != '0' * decimalPlaces &&
          decimalPart.replaceAll('0', '').isNotEmpty;

      if (hasNonZeroDecimal) {
        hasDecimal = true;

        // Pad decimal part to required places (RIGHT padding) or truncate if longer
        if (decimalPart.length > decimalPlaces) {
          decimalPart = decimalPart.substring(0, decimalPlaces);
        } else {
          // Pad on the RIGHT (e.g., .5 → .50 or .500)
          decimalPart = decimalPart.padRight(decimalPlaces, '0');
        }
      }
    } else {
      // No decimal point - don't add one
      integerPart = cleaned.isEmpty ? '0' : cleaned;
    }

    // Remove leading zeros from integer part (but keep "0" if it's just zero)
    integerPart = int.tryParse(integerPart)?.toString() ?? '0';

    // Check if the entire value is zero
    if (integerPart == '0' &&
        (!hasDecimal || decimalPart.replaceAll('0', '').isEmpty)) {
      return '0';
    }

    // Format integer part with Indian numbering
    final formattedInteger = _formatIntegerWithIndianNumbering(integerPart);

    // Only add decimal part if user entered actual decimal digits
    return hasDecimal ? '$formattedInteger.$decimalPart' : formattedInteger;
  }

  // Helper function to format currency value for display (₹ 0.00 format)
  String _formatCurrency(String value) {
    if (value.isEmpty || value == '0') {
      return '₹ 0';
    }

    // Parse the value to handle decimals
    double? numValue = double.tryParse(value);
    if (numValue == null) {
      return '₹ 0';
    }

    // Format with smart decimal handling
    String amountStr = _formatAmountDisplay(numValue, decimalPlaces: 2);

    // Add Indian numbering formatting for the integer part if value is large enough
    if (numValue.abs() >= 1000) {
      final parts = amountStr.split('.');
      String integerPart = parts[0];
      String decimalPart = parts.length > 1 ? parts[1] : '';

      // Format integer part with Indian numbering
      String formattedInteger = _formatIntegerWithIndianNumbering(integerPart);

      return decimalPart.isEmpty
          ? '₹ $formattedInteger'
          : '₹ $formattedInteger.$decimalPart';
    }

    return '₹ $amountStr';
  }

  // Helper function to format double amount for display with Indian numbering
  String _formatAmountForDisplay(double amount, {int decimalPlaces = 2}) {
    final isNegative = amount < 0;

    // Use smart formatting to hide unnecessary decimals
    String smartFormatted =
        _formatAmountDisplay(amount.abs(), decimalPlaces: decimalPlaces);

    // If the value has no decimals or is small, return with sign
    if (amount.abs() < 1000) {
      return '${isNegative ? '-' : ''}$smartFormatted';
    }

    // For larger values, apply Indian numbering to integer part
    final parts = smartFormatted.split('.');
    final integerPart = parts[0];
    final decimalPart = parts.length > 1 ? parts[1] : '';

    // Format integer part with Indian numbering
    final formattedInteger = _formatIntegerWithIndianNumbering(integerPart);

    return decimalPart.isEmpty
        ? '${isNegative ? '-' : ''}$formattedInteger'
        : '${isNegative ? '-' : ''}$formattedInteger.$decimalPart';
  }

  // Helper function to format area value, hiding decimals if they're all zeros
  String _formatAreaDisplay(double value, {int decimalPlaces = 3}) {
    if (value == value.toInt()) {
      // No decimal part, return as integer
      return value.toInt().toString();
    }
    // Has decimal part, format with specified decimal places
    String formatted = value.toStringAsFixed(decimalPlaces);
    // Remove trailing zeros
    formatted = formatted.replaceAll(RegExp(r'\.?0+$'), '');
    return formatted;
  }

  // Helper function to format amount for display, hiding decimals if they're all zeros
  String _formatAmountDisplay(double value, {int decimalPlaces = 2}) {
    if (value == value.toInt()) {
      // No decimal part, return as integer
      return value.toInt().toString();
    }
    // Has decimal part, format with specified decimal places
    String formatted = value.toStringAsFixed(decimalPlaces);
    // Remove trailing zeros
    formatted = formatted.replaceAll(RegExp(r'\.?0+$'), '');
    return formatted;
  }

  // Helper for input/controller text formatting with Indian commas.
  // Keeps storage models unformatted while preserving UI formatting on reload.
  String _formatInputAmount(dynamic value, {int decimalPlaces = 2}) {
    if (value == null) return '';

    double numValue;
    if (value is String) {
      numValue = double.tryParse(value.replaceAll(',', '').trim()) ?? 0.0;
    } else if (value is num) {
      numValue = value.toDouble();
    } else {
      return '';
    }

    if (numValue == 0.0) return '';
    final compact =
        _formatAmountDisplay(numValue, decimalPlaces: decimalPlaces);
    return _formatAmount(compact, decimalPlaces: decimalPlaces);
  }

  double get _totalNonSellableArea {
    return _nonSellableAreas.fold(0.0,
        (sum, area) => sum + (double.tryParse(area['area'] ?? '0') ?? 0.0));
  }

  double get _totalAmenityArea {
    return _amenityAreas.fold(0.0,
        (sum, area) => sum + (double.tryParse(area['area'] ?? '0') ?? 0.0));
  }

  bool get _hasAmenityAreaSectionData {
    for (int i = 0; i < _amenityAreas.length; i++) {
      final name =
          (_amenityNameControllers[i]?.text ?? _amenityAreas[i]['name'] ?? '')
              .trim();
      if (name.isEmpty) continue;

      final normalizedName = name.toLowerCase();
      final defaultAutoLabel = 'amenity area ${i + 1}';
      final areaValue = _getAmenityAreaValue(i);
      final allInCostValue = _getAmenityAllInCostValue(i);

      // Show Amenity Area tab only after user meaningfully enters amenity data.
      if (normalizedName != defaultAutoLabel ||
          areaValue > 0 ||
          allInCostValue > 0) {
        return true;
      }
    }
    return false;
  }

  void _addAmenityAreaRow() {
    setState(() {
      final newIndex = _amenityAreas.length;
      final nextLabel = 'Amenity Area ${newIndex + 1}';
      _amenityAreas.add({
        'id': '',
        'name': nextLabel,
        'area': '0.00',
        'allInCost': '0.00',
      });
      _amenityNameControllers[newIndex] =
          TextEditingController(text: nextLabel);
      _amenityAreaControllers[newIndex] = TextEditingController();
      _amenityAllInCostControllers[newIndex] = TextEditingController();
      _amenityNameFocusNodes[newIndex] = FocusNode();
      _amenityAreaFocusNodes[newIndex] = FocusNode();
      _amenityAllInCostFocusNodes[newIndex] = FocusNode();
    });
    _onDataChanged();
  }

  void _removeAmenityAreaRow(int index) {
    setState(() {
      _amenityNameControllers[index]?.dispose();
      _amenityAreaControllers[index]?.dispose();
      _amenityAllInCostControllers[index]?.dispose();
      _amenityNameFocusNodes[index]?.dispose();
      _amenityAreaFocusNodes[index]?.dispose();
      _amenityAllInCostFocusNodes[index]?.dispose();

      _amenityAreas.removeAt(index);

      final oldNameControllers =
          Map<int, TextEditingController>.from(_amenityNameControllers);
      final oldAreaControllers =
          Map<int, TextEditingController>.from(_amenityAreaControllers);
      final oldAllInCostControllers =
          Map<int, TextEditingController>.from(_amenityAllInCostControllers);
      final oldNameFocusNodes =
          Map<int, FocusNode>.from(_amenityNameFocusNodes);
      final oldAreaFocusNodes =
          Map<int, FocusNode>.from(_amenityAreaFocusNodes);
      final oldAllInCostFocusNodes =
          Map<int, FocusNode>.from(_amenityAllInCostFocusNodes);

      _amenityNameControllers.clear();
      _amenityAreaControllers.clear();
      _amenityAllInCostControllers.clear();
      _amenityNameFocusNodes.clear();
      _amenityAreaFocusNodes.clear();
      _amenityAllInCostFocusNodes.clear();

      for (int i = 0; i < _amenityAreas.length; i++) {
        final sourceIndex = i < index ? i : i + 1;
        _amenityNameControllers[i] = oldNameControllers[sourceIndex] ??
            TextEditingController(text: _amenityAreas[i]['name'] ?? '');
        _amenityAreaControllers[i] = oldAreaControllers[sourceIndex] ??
            TextEditingController(
              text: ((_amenityAreas[i]['area'] ?? '')
                          .replaceAll(',', '')
                          .trim() ==
                      '0')
                  ? ''
                  : _amenityAreas[i]['area'] ?? '',
            );
        _amenityAllInCostControllers[i] =
            oldAllInCostControllers[sourceIndex] ??
                TextEditingController(
                  text: ((_amenityAreas[i]['allInCost'] ?? '')
                              .replaceAll(',', '')
                              .trim() ==
                          '0')
                      ? ''
                      : _amenityAreas[i]['allInCost'] ?? '',
                );
        _amenityNameFocusNodes[i] =
            oldNameFocusNodes[sourceIndex] ?? FocusNode();
        _amenityAreaFocusNodes[i] =
            oldAreaFocusNodes[sourceIndex] ?? FocusNode();
        _amenityAllInCostFocusNodes[i] =
            oldAllInCostFocusNodes[sourceIndex] ?? FocusNode();
      }
    });
    _onDataChanged();
  }

  double _getAmenityAreaValue(int index) {
    final raw = (_amenityAreaControllers[index]?.text ??
            _amenityAreas[index]['area'] ??
            '')
        .replaceAll(',', '')
        .replaceAll(' ', '')
        .trim();
    return double.tryParse(raw) ?? 0.0;
  }

  double _getAmenityAllInCostValue(int index) {
    final raw = (_amenityAllInCostControllers[index]?.text ??
            _amenityAreas[index]['allInCost'] ??
            '')
        .replaceAll(',', '')
        .replaceAll('₹', '')
        .replaceAll(' ', '')
        .trim();
    return double.tryParse(raw) ?? 0.0;
  }

  double _getAmenityPlotCostValue(int index) {
    return _getAmenityAreaValue(index) * _getAmenityAllInCostValue(index);
  }

  double get _totalAmenityPlotCost {
    double total = 0.0;
    for (int i = 0; i < _amenityAreas.length; i++) {
      total += _getAmenityPlotCostValue(i);
    }
    return total;
  }

  double get _actualSellingArea {
    // Calculate selling area from all layout plots
    double total = 0.0;
    for (var layout in _layouts) {
      final plots = layout['plots'] as List<dynamic>? ?? [];
      for (var plot in plots) {
        final areaText = plot['area']?.toString() ?? '0';
        final area =
            double.tryParse(areaText.replaceAll(',', '').replaceAll(' ', '')) ??
                0.0;
        total += area;
      }
    }
    return total;
  }

  double get _remainingArea {
    final totalArea = double.tryParse(_totalAreaController.text
            .replaceAll(',', '')
            .replaceAll(' ', '')) ??
        0;
    final approvedSellingAreaDisplay = double.tryParse(_sellingAreaController
            .text
            .replaceAll(',', '')
            .replaceAll(' ', '')) ??
        0;
    return totalArea -
        _totalNonSellableArea -
        _totalAmenityArea -
        approvedSellingAreaDisplay;
  }

  bool get _isApprovedSellingAreaExceedingTotalArea {
    final totalArea = double.tryParse(_totalAreaController.text
            .replaceAll(',', '')
            .replaceAll(' ', '')) ??
        0;
    final sellingArea = double.tryParse(_sellingAreaController.text
            .replaceAll(',', '')
            .replaceAll(' ', '')) ??
        0;
    return sellingArea > totalArea && totalArea > 0;
  }

  double get _estimatedDevelopmentCost {
    final cleaned = _estimatedDevelopmentCostController.text
        .replaceAll(',', '')
        .replaceAll('₹', '')
        .replaceAll(' ', '')
        .trim();
    return double.tryParse(cleaned) ?? 0.0;
  }

  double get _totalPartnerAmount {
    return _partners.fold(0.0, (sum, partner) {
      final amount = double.tryParse(partner['amount'] ?? '0.00') ?? 0.0;
      return sum + amount;
    });
  }

  double get _remainingPartnerAmount {
    return _estimatedDevelopmentCost - _totalPartnerAmount;
  }

  double get _totalExpenses {
    double total = 0.0;
    for (int i = 0; i < _expenses.length; i++) {
      // Prioritize controller text (what's actually in the amount column)
      final controllerAmount = _expenseAmountControllers[i]?.text.trim() ?? '';
      // Remove commas and currency symbols for parsing
      final cleanedAmount = controllerAmount
          .replaceAll(',', '')
          .replaceAll('₹', '')
          .replaceAll(' ', '');
      final amount =
          double.tryParse(cleanedAmount.isEmpty ? '0.00' : cleanedAmount) ??
              0.0;
      total += amount;
    }
    return total;
  }

  double get _remainingBudget {
    return _estimatedDevelopmentCost - _totalExpenses;
  }

  double get _totalSharePercentage {
    if (_estimatedDevelopmentCost == 0) return 0.0;
    return (_totalPartnerAmount / _estimatedDevelopmentCost) * 100;
  }

  double _getPartnerShare(int index) {
    if (_estimatedDevelopmentCost == 0) return 0.0;
    final amount = double.tryParse(_partners[index]['amount'] ?? '0.00') ?? 0.0;
    return (amount / _estimatedDevelopmentCost) * 100;
  }

  // Site/Layouts calculations (all in sqft for internal consistency)
  double get _approvedSellingArea {
    try {
      final text = _sellingAreaController.text;
      if (text.isEmpty) return 0.0;
      final cleaned = text.replaceAll(',', '').replaceAll(' ', '');
      final displayValue = double.tryParse(cleaned) ?? 0.0;
      return AreaUnitUtils.areaFromDisplayToSqft(displayValue, _isSqm);
    } catch (e) {
      return 0.0;
    }
  }

  double get _allocatedArea {
    // Sum of all plot areas across all layouts (canonical sqft)
    double total = 0.0;
    for (int layoutIndex = 0; layoutIndex < _layouts.length; layoutIndex++) {
      final plotsData = _layouts[layoutIndex]['plots'];
      List<Map<String, dynamic>> plots;
      if (plotsData is List) {
        plots = plotsData.map((p) {
          if (p is Map<String, dynamic>) {
            return p;
          } else if (p is Map) {
            return Map<String, dynamic>.from(p);
          } else {
            return <String, dynamic>{};
          }
        }).toList();
      } else {
        plots = [];
      }

      for (int plotIndex = 0; plotIndex < plots.length; plotIndex++) {
        final key = '${layoutIndex}_$plotIndex';
        final areaController = _plotAreaControllers[key];
        if (areaController != null) {
          total += _plotAreaSqftForKey(key, areaController);
        }
      }
    }
    return total;
  }

  double get _remainingSiteArea {
    return _approvedSellingArea - _allocatedArea;
  }

  double get _allInCostPerSqft {
    return _approvedSellingArea > 0
        ? _totalExpenses / _approvedSellingArea
        : 0.0;
  }

  double get _allInCostPerDisplayUnit {
    return AreaUnitUtils.rateFromSqftToDisplay(_allInCostPerSqft, _isSqm);
  }

  double get _allInCostPerDisplayUnitRounded {
    return _roundToDecimals(_allInCostPerDisplayUnit, 2);
  }

  double get _allInCostPerBaseUnit {
    return AreaUnitUtils.rateFromSqftToDisplay(_allInCostPerSqft, _baseIsSqm);
  }

  double get _allInCostPerBaseUnitRounded {
    return _roundToDecimals(_allInCostPerBaseUnit, 2);
  }

  double _areaDisplayTextToSqft(String rawText, bool isSqmUnit) {
    final display = double.tryParse(
            rawText.replaceAll(',', '').replaceAll(' ', '').trim()) ??
        0.0;
    return AreaUnitUtils.areaFromDisplayToSqft(display, isSqmUnit);
  }

  double _plotAreaSqftForKey(String key, [TextEditingController? controller]) {
    final cached = _plotAreaSqftCache[key];
    if (cached != null) return cached;
    final source = controller?.text ?? _plotAreaControllers[key]?.text ?? '';
    final sqft = _areaDisplayTextToSqft(source, _isSqm);
    _plotAreaSqftCache[key] = sqft;
    return sqft;
  }

  void _updatePlotAreaSqftCacheFromText(String key, String text) {
    _plotAreaSqftCache[key] = _areaDisplayTextToSqft(text, _isSqm);
  }

  String _sitePlotAreaDisplayText(int layoutIndex, int plotIndex) {
    final key = '${layoutIndex}_$plotIndex';
    final controllerText = _plotAreaControllers[key]?.text ?? '';
    if (controllerText.trim().isNotEmpty) return controllerText;
    if (layoutIndex < 0 || layoutIndex >= _layouts.length) return '';
    final plotsData = _layouts[layoutIndex]['plots'];
    final plots = plotsData is List ? plotsData : const [];
    if (plotIndex < 0 || plotIndex >= plots.length) return '';
    final area = (plots[plotIndex]['area'] ?? '').toString().trim();
    if (area.isEmpty || area == '0' || area == '0.00') return '';
    final parsed = double.tryParse(area.replaceAll(',', ''));
    return parsed == null ? area : _formatInputAmount(parsed, decimalPlaces: 3);
  }

  void _setSitePlotAreaDisplayText(
    int layoutIndex,
    int plotIndex,
    String displayText,
  ) {
    if (layoutIndex < 0 || layoutIndex >= _layouts.length) return;
    final plotsData = _layouts[layoutIndex]['plots'];
    final plots = plotsData is List ? plotsData : const [];
    if (plotIndex < 0 || plotIndex >= plots.length) return;

    final key = '${layoutIndex}_$plotIndex';
    final controller = _plotAreaControllers.putIfAbsent(
      key,
      () => TextEditingController(),
    );
    controller.value = TextEditingValue(
      text: displayText,
      selection: TextSelection.collapsed(offset: displayText.length),
    );

    final rawValue = displayText.replaceAll(',', '').replaceAll(' ', '').trim();
    _layouts[layoutIndex]['plots'][plotIndex]['area'] =
        rawValue.isEmpty ? '0.00' : rawValue;
    _updatePlotAreaSqftCacheFromText(key, displayText);
  }

  int? _siteAreaIndexFromGlobalPosition(
      int layoutIndex, Offset globalPosition) {
    if (layoutIndex < 0 || layoutIndex >= _layouts.length) return null;
    final plotsData = _layouts[layoutIndex]['plots'];
    final plots = plotsData is List ? plotsData : const [];

    int? closestIndex;
    double closestDistance = double.infinity;

    for (int i = 0; i < plots.length; i++) {
      final key = '${layoutIndex}_$i';
      final cellContext = _plotAreaCellKeys[key]?.currentContext;
      if (cellContext == null) continue;
      final renderObject = cellContext.findRenderObject();
      if (renderObject is! RenderBox || !renderObject.hasSize) continue;
      final topLeft = renderObject.localToGlobal(Offset.zero);
      final rect = topLeft & renderObject.size;
      if (rect.contains(globalPosition)) {
        return i;
      }
      final distance = (globalPosition.dy - rect.center.dy).abs();
      if (distance < closestDistance) {
        closestDistance = distance;
        closestIndex = i;
      }
    }
    return closestIndex;
  }

  Future<void> _finishSiteAreaFillDrag() async {
    final layoutIndex = _siteAreaFillLayoutIndex;
    final sourceIndex = _siteAreaFillSourceIndex;
    final hoverIndex = _siteAreaFillHoverIndex;

    if (mounted) {
      setState(() {
        _isSiteAreaFillDragging = false;
        _siteAreaFillLayoutIndex = null;
        _siteAreaFillSourceIndex = null;
        _siteAreaFillHoverIndex = null;
        _hoveredSiteAreaHandleKey = null;
      });
    } else {
      _isSiteAreaFillDragging = false;
      _siteAreaFillLayoutIndex = null;
      _siteAreaFillSourceIndex = null;
      _siteAreaFillHoverIndex = null;
      _hoveredSiteAreaHandleKey = null;
    }

    if (layoutIndex == null ||
        sourceIndex == null ||
        hoverIndex == null ||
        sourceIndex == hoverIndex ||
        layoutIndex < 0 ||
        layoutIndex >= _layouts.length) {
      return;
    }

    final plotsData = _layouts[layoutIndex]['plots'];
    final plots = plotsData is List ? plotsData : const [];
    if (sourceIndex < 0 ||
        sourceIndex >= plots.length ||
        hoverIndex < 0 ||
        hoverIndex >= plots.length) {
      return;
    }

    final sourceText = _sitePlotAreaDisplayText(layoutIndex, sourceIndex);
    final start = min(sourceIndex, hoverIndex);
    final end = max(sourceIndex, hoverIndex);

    setState(() {
      for (int i = start; i <= end; i++) {
        if (i == sourceIndex) continue;
        _setSitePlotAreaDisplayText(layoutIndex, i, sourceText);
      }
    });

    _preserveLayoutDragUndoUntilDataChange.add(layoutIndex);
    _onDataChanged(immediate: true);
  }

  double _parseDisplayNumber(String rawText) {
    return double.tryParse(
            rawText.replaceAll(',', '').replaceAll(' ', '').trim()) ??
        0.0;
  }

  double _roundToDecimals(double value, int decimals) {
    return double.tryParse(value.toStringAsFixed(decimals)) ?? value;
  }

  double _plotAreaDisplayRoundedForKey(String key,
      [TextEditingController? controller]) {
    final source = controller?.text ?? _plotAreaControllers[key]?.text ?? '';
    return _roundToDecimals(_parseDisplayNumber(source), 3);
  }

  double _plotTotalCostFromRoundedFigures(String key,
      [TextEditingController? controller]) {
    final roundedArea = _plotAreaDisplayRoundedForKey(key, controller);
    final roundedAllIn = _allInCostPerDisplayUnitRounded;
    return _truncateToDecimals(roundedArea * roundedAllIn, 2);
  }

  double _plotTotalCostFromBaseRoundedFigures(String key,
      [TextEditingController? controller]) {
    final areaSqft = _plotAreaSqftForKey(key, controller);
    final baseArea = AreaUnitUtils.areaFromSqftToDisplay(areaSqft, _baseIsSqm);
    final roundedBaseArea = _roundToDecimals(baseArea, 3);
    final roundedBaseAllIn = _allInCostPerBaseUnitRounded;
    return _truncateToDecimals(roundedBaseArea * roundedBaseAllIn, 2);
  }

  double _projectTotalPlotCostFromBaseRoundedFigures() {
    double total = 0.0;
    for (int layoutIndex = 0; layoutIndex < _layouts.length; layoutIndex++) {
      final plotsData = _layouts[layoutIndex]['plots'];
      final plots = plotsData is List ? plotsData : const [];
      for (int plotIndex = 0; plotIndex < plots.length; plotIndex++) {
        final key = '${layoutIndex}_$plotIndex';
        final areaController = _plotAreaControllers[key];
        if (areaController != null) {
          total += _plotTotalCostFromBaseRoundedFigures(key, areaController);
        }
      }
    }
    return total;
  }

  double _plotTotalCostFromCurrentRoundedFigures(String key,
      [TextEditingController? controller]) {
    return _plotTotalCostFromRoundedFigures(key, controller);
  }

  // Keep money at fixed decimals without rounding up (truncate only).
  double _truncateToDecimals(double value, int decimals) {
    if (decimals < 0) return value;
    double factor = 1.0;
    for (int i = 0; i < decimals; i++) {
      factor *= 10.0;
    }
    return value >= 0
        ? (value * factor).floorToDouble() / factor
        : (value * factor).ceilToDouble() / factor;
  }

  double get _totalPurchaseRate {
    // Calculate as sum of all-in cost values from the fourth column in the plots table
    // This is the sum of actual all-in cost values shown for each plot
    final allInCost = _allInCostPerDisplayUnit;

    double total = 0.0;
    for (int layoutIndex = 0; layoutIndex < _layouts.length; layoutIndex++) {
      final plotsData = _layouts[layoutIndex]['plots'];
      List<Map<String, dynamic>> plots;
      if (plotsData is List) {
        plots = plotsData.map((p) {
          if (p is Map<String, dynamic>) {
            return p;
          } else if (p is Map) {
            return Map<String, dynamic>.from(p);
          } else {
            return <String, dynamic>{};
          }
        }).toList();
      } else {
        plots = [];
      }

      for (int plotIndex = 0; plotIndex < plots.length; plotIndex++) {
        final key = '${layoutIndex}_$plotIndex';
        final areaController = _plotAreaControllers[key];
        if (areaController != null) {
          final area = _plotAreaSqftForKey(key, areaController);
          // Only sum for plots with area > 0
          if (area > 0) {
            // Add the all-in cost for this plot (same rate for all plots)
            total += allInCost;
          }
        }
      }
    }

    // Return sum of all-in cost column values
    return total;
  }

  double get _totalPlotCost {
    // Always fixed to project base unit (not current display toggle).
    return _projectTotalPlotCostFromBaseRoundedFigures();
  }

  bool get _hasPartnerValidationErrors {
    if (_partners.isEmpty) return false;

    // Check if any partner has validation errors
    for (int i = 0; i < _partners.length; i++) {
      // Check name field - prioritize controller text, fallback to partner data
      final controllerName = _partnerNameControllers[i]?.text.trim() ?? '';
      final partnerName = _partners[i]['name']?.toString().trim() ?? '';
      final nameEmpty = controllerName.isEmpty && partnerName.isEmpty;

      // Check amount field - prioritize controller text, fallback to partner data
      final controllerAmount = _partnerAmountControllers[i]?.text.trim() ?? '';
      final partnerAmount = _partners[i]['amount']?.toString().trim() ?? '';
      final amountEmpty =
          (controllerAmount.isEmpty || controllerAmount == '0.00') &&
              (partnerAmount.isEmpty || partnerAmount == '0.00');

      // Check if exceeding estimated development cost
      final exceedsAmount = _totalPartnerAmount > _estimatedDevelopmentCost &&
          _estimatedDevelopmentCost > 0;

      if (nameEmpty || amountEmpty || exceedsAmount) {
        return true;
      }
    }

    // Check if remaining budget is red (not fully allocated or exceeds)
    final hasPartnerData = _partners.any((p) =>
        (p['name']?.toString().trim().isNotEmpty ?? false) ||
        ((double.tryParse(
                    (p['amount'] ?? '0').toString().replaceAll(',', '')) ??
                0) >
            0));
    final noDevelopmentCost = _estimatedDevelopmentCost == 0 && hasPartnerData;
    final remaining = _remainingPartnerAmount;
    final exceedsAmount = _totalPartnerAmount > _estimatedDevelopmentCost &&
        _estimatedDevelopmentCost > 0;

    // Show error if remaining budget is red
    if (noDevelopmentCost || remaining != 0 || exceedsAmount) {
      return true;
    }

    // Show error if total share allocated is red (not 100%)
    if (_totalSharePercentage != 100 && (noDevelopmentCost || exceedsAmount)) {
      return true;
    }

    return false;
  }

  bool get _hasAboutValidationErrors {
    // Check if project name is empty
    final projectNameEmpty = _projectNameController.text.trim().isEmpty;

    // Check if location link is invalid
    final locationValue = _googleMapsLinkController.text.trim();
    final uri = Uri.tryParse(locationValue);
    final validMapPattern = RegExp(
        r'^(https?://)?(www\.)?(google\.com/maps|goo\.gl/maps|maps\.app\.goo\.gl|share\.google/)[\w\-]+',
        caseSensitive: false);
    final isGoogleSearchLocation = uri != null &&
        uri.host.contains('google.com') &&
        uri.path.contains('search') &&
        (uri.queryParameters.containsKey('kgmid') ||
            uri.queryParameters.containsKey('kgs'));
    final isMapsAppGooGl = uri != null && uri.host.contains('maps.app.goo.gl');
    final isShareGoogle = uri != null && uri.host.contains('share.google');
    final locationValid = locationValue.isNotEmpty &&
        (isGoogleSearchLocation ||
            isMapsAppGooGl ||
            isShareGoogle ||
            validMapPattern.hasMatch(locationValue));

    // Empty location is warning-only, not an error.
    final locationInvalid = locationValue.isNotEmpty && !locationValid;
    return projectNameEmpty || locationInvalid;
  }

  bool get _hasAboutWarningOnlyState {
    if (_hasAboutValidationErrors) return false;
    final addressEmpty = _projectAddressController.text.trim().isEmpty;
    final locationEmpty = _googleMapsLinkController.text.trim().isEmpty;
    return addressEmpty || locationEmpty;
  }

  bool get _hasExpenseValidationErrors {
    if (_expenses.isEmpty) return false;

    // Check if any expense has validation errors (red box shadows)
    for (int i = 0; i < _expenses.length; i++) {
      // Check expense item field - prioritize controller text, fallback to expense data
      final controllerItem = _expenseItemControllers[i]?.text.trim() ?? '';
      final expenseItem = _expenses[i]['item']?.toString().trim() ?? '';
      final itemEmpty = (controllerItem.isEmpty) &&
          (expenseItem.isEmpty || expenseItem == null);

      // Check amount field - prioritize controller text, fallback to expense data
      final controllerAmount = _expenseAmountControllers[i]?.text.trim() ?? '';
      final expenseAmount = _expenses[i]['amount']?.toString().trim() ?? '';
      // Remove commas for checking
      final cleanedControllerAmount = controllerAmount
          .replaceAll(',', '')
          .replaceAll('₹', '')
          .replaceAll(' ', '');
      final cleanedExpenseAmount = expenseAmount
          .replaceAll(',', '')
          .replaceAll('₹', '')
          .replaceAll(' ', '');
      final amountEmpty = (cleanedControllerAmount.isEmpty ||
              cleanedControllerAmount == '0.00') &&
          (cleanedExpenseAmount.isEmpty || cleanedExpenseAmount == '0.00');

      if (itemEmpty || amountEmpty) {
        return true;
      }
    }

    return false;
  }

  bool get _hasNonSellableSectionValidationErrors {
    bool hasNameWithoutValue = false;

    for (int i = 0; i < _nonSellableAreas.length; i++) {
      final areaRaw = (_nonSellableAreaControllers[i]?.text ??
              _nonSellableAreas[i]['area'] ??
              '')
          .replaceAll(',', '')
          .replaceAll(' ', '')
          .trim();
      final areaValue = double.tryParse(areaRaw) ?? 0;
      final nameValue = (_nonSellableNameControllers[i]?.text ??
              _nonSellableAreas[i]['name'] ??
              '')
          .trim();

      if (nameValue.isNotEmpty && areaValue == 0) {
        hasNameWithoutValue = true;
        break;
      }
    }

    final remainingAreaIsNegative = _remainingArea < 0;
    return hasNameWithoutValue || remainingAreaIsNegative;
  }

  bool get _hasAmenitySectionValidationErrors {
    if (_amenityAreas.isEmpty) return false;

    bool hasNameWithoutValue = false;
    for (int i = 0; i < _amenityAreas.length; i++) {
      if (_isAmenityPlaceholderRow(i)) {
        continue;
      }
      final areaRaw =
          (_amenityAreaControllers[i]?.text ?? _amenityAreas[i]['area'] ?? '')
              .replaceAll(',', '')
              .replaceAll(' ', '')
              .trim();
      final areaValue = double.tryParse(areaRaw) ?? 0;
      final nameValue =
          (_amenityNameControllers[i]?.text ?? _amenityAreas[i]['name'] ?? '')
              .trim();
      if (nameValue.isNotEmpty && areaValue == 0) {
        hasNameWithoutValue = true;
        break;
      }
    }

    final remainingAreaIsNegative = _remainingArea < 0;
    return hasNameWithoutValue || remainingAreaIsNegative;
  }

  bool get _hasAmenityDataEntryValidationErrors {
    if (_amenityAreas.isEmpty || !_hasAmenityAreaSectionData) return false;
    for (int i = 0; i < _amenityAreas.length; i++) {
      if (_isAmenityPlaceholderRow(i)) {
        continue;
      }
      final areaRaw =
          (_amenityAreaControllers[i]?.text ?? _amenityAreas[i]['area'] ?? '')
              .replaceAll(',', '')
              .replaceAll(' ', '')
              .trim();
      final areaValue = double.tryParse(areaRaw) ?? 0;
      final allInCostRaw = (_amenityAllInCostControllers[i]?.text ??
              _amenityAreas[i]['allInCost'] ??
              '')
          .replaceAll(',', '')
          .replaceAll('₹', '')
          .replaceAll(' ', '')
          .trim();
      final allInCostValue = double.tryParse(allInCostRaw) ?? 0;
      final nameValue =
          (_amenityNameControllers[i]?.text ?? _amenityAreas[i]['name'] ?? '')
              .trim();
      final hasRedShadowInAreaSection = areaValue == 0 || nameValue.isEmpty;
      final hasRedShadowInAmenityDataEntry =
          _hasAmenityAreaSectionData && allInCostValue == 0;
      if (hasRedShadowInAreaSection || hasRedShadowInAmenityDataEntry) {
        return true;
      }
    }
    return false;
  }

  bool _isAmenityPlaceholderRow(int index) {
    if (index < 0 || index >= _amenityAreas.length) return true;
    final existingId = (_amenityAreas[index]['id'] ?? '').trim();
    if (existingId.isNotEmpty) return false;
    final name = (_amenityNameControllers[index]?.text ??
            _amenityAreas[index]['name'] ??
            '')
        .trim();
    final normalizedName = name.toLowerCase();
    final defaultAutoLabel = 'amenity area ${index + 1}';
    final areaValue = _getAmenityAreaValue(index);
    final allInCostValue = _getAmenityAllInCostValue(index);
    final hasDefaultUntouchedName =
        name.isEmpty || normalizedName == defaultAutoLabel;
    return hasDefaultUntouchedName && areaValue == 0 && allInCostValue == 0;
  }

  bool get _hasProjectManagerValidationErrors {
    if (_projectManagers.isEmpty) return false;

    // Check if any project manager has validation errors (red box shadows)
    for (int i = 0; i < _projectManagers.length; i++) {
      // Check name field - prioritize controller text, fallback to stored value
      final controllerName =
          _projectManagerNameControllers[i]?.text.trim() ?? '';
      final managerName = _projectManagers[i]['name']?.toString().trim() ?? '';
      final nameEmpty = controllerName.isEmpty && managerName.isEmpty;

      // Get compensation type
      final compensationType = _projectManagerCompensation[i] ?? '';
      final compensationEmpty = compensationType.isEmpty;

      // Get earning type
      String selectedEarningType = '';
      try {
        selectedEarningType = _projectManagerEarningType[i] ?? '';
      } catch (e) {
        selectedEarningType = '';
      }

      // Red box shadow appears when:
      // 1. Name is empty (regardless of compensation)
      if (nameEmpty) {
        return true;
      }

      // 2. Compensation is empty (regardless of name)
      if (compensationEmpty) {
        return true;
      }

      // 3. Compensation is "Percentage Bonus" AND earning type is empty
      // Note: Fixed Fee and Monthly Fee don't require earning type
      if (compensationType == 'Percentage Bonus' &&
          selectedEarningType.isEmpty) {
        return true;
      }
    }

    return false;
  }

  bool get _isProjectManagerFirstRowWarningState {
    if (_projectManagers.length != 1) return false;

    final controllerName = _projectManagerNameControllers[0]?.text.trim() ?? '';
    final managerName = _projectManagers[0]['name']?.toString().trim() ?? '';
    final nameEmpty = controllerName.isEmpty && managerName.isEmpty;

    final compensationType = _projectManagerCompensation[0] ?? '';
    final compensationEmpty = compensationType.isEmpty;

    return nameEmpty && compensationEmpty;
  }

  bool get _hasAgentValidationErrors {
    if (_agents.isEmpty) return false;

    // Check if any agent has validation errors (red box shadows)
    for (int i = 0; i < _agents.length; i++) {
      // Check name field - prioritize controller text, fallback to stored value
      final controllerName = _agentNameControllers[i]?.text.trim() ?? '';
      final agentName = _agents[i]['name']?.toString().trim() ?? '';
      final nameEmpty = controllerName.isEmpty && agentName.isEmpty;

      // Get compensation type
      final compensationType = _agentCompensation[i] ?? '';
      final compensationEmpty =
          compensationType.isEmpty || compensationType == 'None';

      // Get earning type
      String selectedEarningType = '';
      try {
        selectedEarningType = _agentEarningType[i] ?? '';
      } catch (e) {
        selectedEarningType = '';
      }

      // Red box shadow appears when:
      // 1. Name is empty (regardless of compensation)
      if (nameEmpty) {
        return true;
      }

      // 2. Compensation is empty (regardless of name)
      if (compensationEmpty) {
        return true;
