            color: _projectManagerFixedFeeFocusNodes[index]!.hasFocus
                ? const Color(0xFF0C8CE9)
                : Colors.black.withOpacity(0.15),
            blurRadius: 2,
            offset: const Offset(0, 0),
            spreadRadius: 0,
          ),
