  // Helper widget to build focus-aware input container with dynamic shadow
  Widget _buildFocusAwareInputContainer({
    required Widget child,
    required FocusNode focusNode,
    VoidCallback? onFocusLost,
    double width = double.infinity,
    double height = 40,
    Color backgroundColor = const Color(0xFFF8F9FA),
    double borderRadius = 8,
    Color? defaultShadowColor,
  }) {
    return _FocusAwareInputContainer(
      focusNode: focusNode,
      onFocusLost: onFocusLost,
      width: width,
      height: height,
      backgroundColor: backgroundColor,
      borderRadius: borderRadius,
      defaultShadowColor: defaultShadowColor,
      child: child,
    );
  }

  void _convertAllAreaValuesOnUnitChange(bool oldIsSqm, bool newIsSqm) {
    double toSqft(double v) => oldIsSqm ? v * AreaUnitUtils.sqmToSqft : v;
    double fromSqft(double sqft) =>
        newIsSqm ? sqft * AreaUnitUtils.sqftToSqm : sqft;
    double normalizeConvertedArea(double v) {
      // Avoid visible round-trip drift like 1200 -> sqm -> 1200.003
      // when switching units using rounded display values.
      final rounded3 = double.parse(v.toStringAsFixed(3));
      final nearestInteger = rounded3.roundToDouble();
      if ((rounded3 - nearestInteger).abs() <= 0.005) {
        return nearestInteger;
      }
      return rounded3;
    }

    double rateToSqft(double v) => oldIsSqm ? v / AreaUnitUtils.sqmToSqft : v;
    double rateFromSqft(double perSqft) =>
        newIsSqm ? perSqft * AreaUnitUtils.sqmToSqft : perSqft;

    final totalDisplay = double.tryParse(_totalAreaController.text
            .replaceAll(',', '')
            .replaceAll(' ', '')) ??
        0;
    _totalAreaController.text = totalDisplay == 0
        ? ''
        : _formatInputAmount(
            normalizeConvertedArea(fromSqft(toSqft(totalDisplay))),
            decimalPlaces: 3,
          );

    final sellingDisplay = double.tryParse(_sellingAreaController.text
            .replaceAll(',', '')
            .replaceAll(' ', '')) ??
        0;
    _sellingAreaController.text = sellingDisplay == 0
        ? ''
        : _formatInputAmount(
            normalizeConvertedArea(fromSqft(toSqft(sellingDisplay))),
            decimalPlaces: 3,
          );

    for (int i = 0; i < _nonSellableAreaControllers.length; i++) {
      final c = _nonSellableAreaControllers[i];
      if (c != null) {
        final v =
            double.tryParse(c.text.replaceAll(',', '').replaceAll(' ', '')) ??
                0;
        c.text = v == 0
            ? ''
            : _formatInputAmount(
                normalizeConvertedArea(fromSqft(toSqft(v))),
                decimalPlaces: 3,
              );
      }
    }
    for (int i = 0; i < _nonSellableAreas.length; i++) {
      final a = double.tryParse(
              _nonSellableAreas[i]['area']?.toString().replaceAll(',', '') ??
                  '0') ??
          0;
      _nonSellableAreas[i]['area'] = a == 0
          ? ''
          : _formatAreaDecimal(
              normalizeConvertedArea(fromSqft(toSqft(a))),
            );
    }
    for (int i = 0; i < _amenityAreaControllers.length; i++) {
      final c = _amenityAreaControllers[i];
      if (c != null) {
        final v =
            double.tryParse(c.text.replaceAll(',', '').replaceAll(' ', '')) ??
                0;
        c.text = v == 0
            ? ''
            : _formatInputAmount(
                normalizeConvertedArea(fromSqft(toSqft(v))),
                decimalPlaces: 3,
              );
      }
    }
    for (int i = 0; i < _amenityAreas.length; i++) {
      final a = double.tryParse(
              _amenityAreas[i]['area']?.toString().replaceAll(',', '') ??
                  '0') ??
          0;
      _amenityAreas[i]['area'] = a == 0
          ? ''
          : _formatAreaDecimal(
              normalizeConvertedArea(fromSqft(toSqft(a))),
            );
    }
    for (int i = 0; i < _amenityAllInCostControllers.length; i++) {
      final c = _amenityAllInCostControllers[i];
      if (c != null) {
        final v = double.tryParse(c.text
                .replaceAll(',', '')
                .replaceAll('₹', '')
                .replaceAll(' ', '')) ??
            0;
        c.text = v == 0 ? '' : _formatInputAmount(rateFromSqft(rateToSqft(v)));
      }
    }
    for (int i = 0; i < _amenityAreas.length; i++) {
      final r = double.tryParse((_amenityAreas[i]['allInCost'] ?? '0')
              .toString()
              .replaceAll(',', '')
              .replaceAll('₹', '')
              .replaceAll(' ', '')) ??
          0;
      _amenityAreas[i]['allInCost'] =
          r == 0 ? '' : _formatInputAmount(rateFromSqft(rateToSqft(r)));
    }
    for (final entry in _plotAreaControllers.entries) {
      final key = entry.key;
      final cachedSqft = _plotAreaSqftCache[key];
      final areaSqft =
          cachedSqft ?? _areaDisplayTextToSqft(entry.value.text, oldIsSqm);
      _plotAreaSqftCache[key] = areaSqft;
      if (areaSqft > 0) {
        entry.value.text = _formatInputAmount(
          normalizeConvertedArea(fromSqft(areaSqft)),
          decimalPlaces: 3,
        );
      } else {
        entry.value.text = '';
      }
    }
    // Convert agent per sqft/sqm fee (rates)
    for (final i in _agentPerSqftFeeControllers.keys) {
      final c = _agentPerSqftFeeControllers[i];
      if (c != null && (_agentCompensation[i] ?? '') == 'Per Sqft Fee') {
        final v =
            double.tryParse(c.text.replaceAll(',', '').replaceAll(' ', '')) ??
                0;
        if (v > 0) {
          c.text = _formatInputAmount(rateFromSqft(rateToSqft(v)));
        }
      }
    }
    for (final i in _agentPerSqftFee.keys) {
      if ((_agentCompensation[i] ?? '') == 'Per Sqft Fee') {
        final v = double.tryParse(
                (_agentPerSqftFee[i] ?? '0').toString().replaceAll(',', '')) ??
            0;
        if (v > 0) {
          _agentPerSqftFee[i] = _formatInputAmount(rateFromSqft(rateToSqft(v)));
          _agents[i]['perSqftFee'] = _agentPerSqftFee[i];
        }
      }
    }
  }

  Widget _buildAreaUnitSelector() {
    return const AreaUnitDisplay(
      unitLabel: AreaUnitUtils.sqmUnitLabel,
    );
  }

