                    ),
                    if (_showStickySiteLayoutsToolbar &&
                        _activeTab == ProjectTab.site &&
                        !_isLoadingData &&
                        _layouts.isNotEmpty)
                      Positioned(
                        top: 0,
                        left: 24,
                        right: 24,
                        child: Container(
                          padding: const EdgeInsets.only(top: 8, bottom: 8),
                          color: Colors.white,
                          child: _buildSiteLayoutsToolbarRow(),
                        ),
                      ),
                  ],
                ),
              ),
            ],
          ),
        ),
      ],
    );
