  Widget _buildAreaSectionToggleIcon({
    required bool isExpanded,
    required VoidCallback onTap,
  }) {
    return GestureDetector(
      behavior: HitTestBehavior.opaque,
      onTap: onTap,
      child: SizedBox(
        width: 24,
        height: 24,
        child: Center(
          child: SvgPicture.asset(
            isExpanded
                ? 'assets/images/amenity_dropdown.svg'
                : 'assets/images/amenity_dropup.svg',
            width: 20,
            height: 20,
            fit: BoxFit.contain,
            placeholderBuilder: (context) => const SizedBox(
              width: 20,
              height: 20,
            ),
            errorBuilder: (context, error, stackTrace) => const SizedBox(
              width: 20,
              height: 20,
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildAmenityAreaSectionCard() {
    final areaUnit = _areaUnitSuffix;
    return Container(
      width: 750,
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: const Color(0xFFF8F9FA),
        borderRadius: BorderRadius.circular(8),
        boxShadow: [
          BoxShadow(
            color: _hasAmenitySectionValidationErrors
                ? Colors.red.withOpacity(0.6)
                : Colors.black.withOpacity(0.25),
            blurRadius: 2,
            offset: const Offset(0, 0),
            spreadRadius: 0,
          ),
        ],
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(
                'Amenity Area (If applicable)',
                style: GoogleFonts.inter(
                  fontSize: 14,
                  fontWeight: FontWeight.w500,
                  color: Colors.black,
                ),
              ),
              _buildAreaSectionToggleIcon(
                isExpanded: _isAmenityAreaExpanded,
                onTap: () {
                  setState(() {
                    _isAmenityAreaExpanded = !_isAmenityAreaExpanded;
                  });
                },
              ),
            ],
          ),
          const SizedBox(height: 8),
          RichText(
            text: TextSpan(
              children: [
                TextSpan(
                  text: 'Total Amenity Area: ',
                  style: GoogleFonts.inter(
                    fontSize: 14,
                    fontWeight: FontWeight.w500,
                    color: const Color(0xFF5C5C5C),
                  ),
                ),
                TextSpan(
                  text: '${_formatAreaDisplay(_totalAmenityArea)} $areaUnit',
                  style: GoogleFonts.inter(
                    fontSize: 14,
                    fontWeight: FontWeight.w400,
                    color: const Color(0xFF5C5C5C),
                  ),
                ),
              ],
            ),
          ),
          if (_isAmenityAreaExpanded) ...[
            const SizedBox(height: 8),
            ..._amenityAreas.asMap().entries.map((entry) {
              final index = entry.key;
              return Padding(
                padding: EdgeInsets.only(
                  bottom: index == _amenityAreas.length - 1 ? 0 : 8,
                ),
                child: Row(
                  children: [
                    _buildFocusAwareInputContainer(
                      focusNode: _amenityAreaFocusNodes.putIfAbsent(
                        index,
                        () => FocusNode(),
                      ),
                      width: 184,
                      height: 40,
                      backgroundColor: Colors.white,
                      defaultShadowColor: (() {
                        final raw = (_amenityAreas[index]['area'] ?? '')
                            .toString()
                            .replaceAll(',', '')
                            .replaceAll(' ', '')
                            .trim();
                        return (raw.isEmpty ||
                                raw == '0' ||
                                raw == '0.0' ||
                                raw == '0.00')
                            ? Colors.red
                            : Colors.black.withOpacity(0.15);
                      })(),
                      onFocusLost: () {
                        final controller = _amenityAreaControllers[index];
                        if (controller == null) return;
                        final cleaned = controller.text
                            .replaceAll(',', '')
                            .replaceAll(' ', '');
                        final formatted =
                            _formatAmount(cleaned, decimalPlaces: 3);
                        controller.value = TextEditingValue(
                          text: formatted,
                          selection:
                              TextSelection.collapsed(offset: formatted.length),
                        );
                        setState(() {
                          _amenityAreas[index]['area'] =
                              formatted.replaceAll(',', '');
                        });
                        _onDataChanged();
                      },
                      child: Center(
                        child: Row(
                          mainAxisAlignment: MainAxisAlignment.spaceBetween,
                          crossAxisAlignment: CrossAxisAlignment.center,
                          children: [
                            Expanded(
                              child: Builder(
                                builder: (context) {
                                  if (_amenityAreaControllers[index] == null) {
                                    _amenityAreaControllers[index] =
                                        TextEditingController();
                                  }
                                  return DecimalInputField(
                                    hintText: '0',
                                    controller: _amenityAreaControllers[index]!,
                                    focusNode: _amenityAreaFocusNodes[index],
                                    decimalPlaces: 3,
                                    inputFormatters: [
                                      IndianNumberFormatter(maxIntegerDigits: 9)
                                    ],
                                    onTap: () {
                                      final cleaned =
                                          _amenityAreaControllers[index]!
                                              .text
                                              .replaceAll(',', '')
                                              .replaceAll(' ', '')
                                              .trim();
                                      if (cleaned == '0' || cleaned == '0.00') {
                                        _amenityAreaControllers[index]!.text =
                                            '';
                                        _amenityAreaControllers[index]!
                                                .selection =
                                            const TextSelection.collapsed(
                                                offset: 0);
                                        setState(() {});
                                      }
                                    },
                                    onChanged: (value) {
                                      final rawValue = value
                                          .replaceAll(',', '')
                                          .replaceAll(' ', '');
                                      setState(() {
                                        _amenityAreas[index]['area'] =
                                            rawValue.isEmpty
                                                ? '0.00'
                                                : rawValue;
                                      });
                                      _onDataChanged();
                                    },
                                    onEditingComplete: () {
                                      final cleaned =
                                          _amenityAreaControllers[index]!
                                              .text
                                              .replaceAll(',', '')
                                              .replaceAll(' ', '');
                                      final formatted = _formatAmount(cleaned,
                                          decimalPlaces: 3);
                                      _amenityAreaFocusNodes[index]?.unfocus();
                                      _amenityAreaControllers[index]!.value =
                                          TextEditingValue(
                                        text: formatted,
                                        selection: TextSelection.collapsed(
                                            offset: formatted.length),
                                      );
                                      setState(() {
                                        _amenityAreas[index]['area'] =
                                            formatted.replaceAll(',', '');
                                      });
                                      _onDataChanged();
                                    },
                                    textInputAction: TextInputAction.done,
                                    contentPadding: const EdgeInsets.only(
                                      left: 0,
                                      right: 8,
                                      top: 8,
                                      bottom: 8,
                                    ),
                                  );
                                },
                              ),
                            ),
                            Padding(
                              padding: const EdgeInsets.only(left: 8),
                              child: Text(
                                _areaUnitSuffix,
                                style: GoogleFonts.inter(
                                  fontSize: 14,
                                  fontWeight: FontWeight.normal,
                                  color: const Color(0xFF5C5C5C),
                                ),
                              ),
                            ),
                          ],
                        ),
                      ),
                    ),
                    const SizedBox(width: 8),
                    _buildFocusAwareInputContainer(
                      focusNode: _amenityNameFocusNodes.putIfAbsent(
                        index,
                        () => FocusNode(),
                      ),
                      width: 250,
                      height: 40,
                      backgroundColor: Colors.white,
                      defaultShadowColor:
                          (_amenityAreas[index]['name']?.isEmpty ?? true)
                              ? Colors.red
                              : Colors.black.withOpacity(0.15),
                      onFocusLost: _onDataChanged,
                      child: Align(
                        alignment: Alignment.centerLeft,
                        child: TextField(
                          textAlignVertical: TextAlignVertical.top,
                          focusNode: _amenityNameFocusNodes[index],
                          controller: _amenityNameControllers[index],
                          textInputAction: TextInputAction.done,
                          onChanged: (value) {
                            setState(() {
                              _amenityAreas[index]['name'] = value;
                            });
                            _onDataChanged();
                          },
                          onEditingComplete: () {
                            _amenityNameFocusNodes[index]?.unfocus();
                            _onDataChanged();
                          },
                          decoration: InputDecoration(
                            hintText: 'Amenity Area ${index + 1}',
                            hintStyle: GoogleFonts.inter(
                              fontSize: 14,
                              fontWeight: FontWeight.w500,
                              color: const Color.fromARGB(191, 173, 173, 173),
                            ),
                            border: InputBorder.none,
                            contentPadding:
                                const EdgeInsets.symmetric(vertical: 0),
                            isDense: true,
                            alignLabelWithHint: false,
                          ),
                          style: GoogleFonts.inter(
                            fontSize: 14,
                            fontWeight: FontWeight.w500,
                            color: Colors.black,
                          ),
                          maxLines: 1,
                          inputFormatters: [
                            FilteringTextInputFormatter.singleLineFormatter,
                          ],
                        ),
                      ),
                    ),
                    const SizedBox(width: 8),
                    GestureDetector(
                      onTap: () => _removeAmenityAreaRow(index),
                      child: Container(
                        height: 36,
                        padding: const EdgeInsets.symmetric(
                            horizontal: 16, vertical: 4),
                        decoration: BoxDecoration(
                          color: Colors.white,
                          borderRadius: BorderRadius.circular(8),
                          boxShadow: [
                            BoxShadow(
                              color: Colors.black.withOpacity(0.25),
                              blurRadius: 2,
                              offset: const Offset(0, 0),
                              spreadRadius: 0,
                            ),
                          ],
                        ),
                        child: Center(
                          child: Text(
                            'Remove',
                            style: GoogleFonts.inter(
                              fontSize: 14,
                              fontWeight: FontWeight.normal,
                              color: Colors.red,
                            ),
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
              );
            }),
            const SizedBox(height: 8),
            RichText(
              text: TextSpan(
                children: [
                  TextSpan(
                    text: 'Remaining Area: ',
                    style: GoogleFonts.inter(
                      fontSize: 14,
                      fontWeight: FontWeight.w500,
                      color: _remainingArea == 0
                          ? const Color(0xFF06AB00)
                          : Colors.red,
                    ),
                  ),
                  TextSpan(
                    text: _remainingArea < 0
                        ? '${_formatAreaDisplay(_remainingArea)} $areaUnit [Exceeding Total Area ($areaUnit)]'
                        : '${_formatAreaDisplay(_remainingArea)} $areaUnit',
                    style: GoogleFonts.inter(
                      fontSize: 14,
                      fontWeight: FontWeight.w400,
                      color: _remainingArea == 0
                          ? const Color(0xFF06AB00)
                          : Colors.red,
                    ),
                  ),
                ],
              ),
            ),
            const SizedBox(height: 8),
            GestureDetector(
              onTap: _addAmenityAreaRow,
              child: Container(
                height: 36,
                padding: const EdgeInsets.symmetric(horizontal: 8),
                decoration: BoxDecoration(
                  color: const Color(0xFF0C8CE9),
                  borderRadius: BorderRadius.circular(8),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.25),
                      blurRadius: 2,
                      offset: const Offset(0, 0),
                    ),
                  ],
                ),
                child: Row(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(
                      'Add Amenity Area',
                      style: GoogleFonts.inter(
                        fontSize: 14,
                        fontWeight: FontWeight.w400,
                        color: Colors.white,
                      ),
                    ),
                    const SizedBox(width: 8),
                    SvgPicture.asset(
                      'assets/images/Cretae_new_projet_white.svg',
                      width: 12,
                      height: 12,
                      fit: BoxFit.contain,
                      placeholderBuilder: (context) => const SizedBox(
                        width: 12,
                        height: 12,
                      ),
                      errorBuilder: (context, error, stackTrace) {
                        return const SizedBox(
                          width: 12,
                          height: 12,
                          child: Icon(
                            Icons.add,
                            size: 12,
                            color: Colors.white,
                          ),
                        );
                      },
                    ),
                  ],
                ),
              ),
            ),
          ],
        ],
      ),
    );
  }

