                children: [
                  // Header
                  Container(
                    width: 60,
                    height: 48,
                    decoration: BoxDecoration(
                      color: const Color(0xFF707070).withOpacity(0.2),
                      border: Border.all(color: Colors.black, width: 1.0),
                      borderRadius: const BorderRadius.only(
                        topLeft: Radius.circular(8),
