                                        final rawValue = value
                                            .replaceAll(',', '')
                                            .replaceAll('₹', '')
                                            .replaceAll(' ', '');
                                        setState(() {
                                          // Avoid transient autosave to 0 while user is mid-edit.
                                          // Commit zero/empty only on editing complete / tap outside.
