                                String displayValue;
                                Color textColor;

                                if (remaining < 0) {
                                  // Negative (over budget) - red
                                  displayValue =
                                      '- ₹ $formattedAmount [Over Budget]';
                                  textColor = Colors.red;
                                } else if (remaining == 0) {
                                  // Zero - current color (black)
                                  displayValue = '₹ $formattedAmount';
                                  textColor = Colors.black;
                                } else {
                                  // Positive - green
                                  displayValue = '₹ $formattedAmount';
                                  textColor = const Color(0xFF06AB00);
                                }

