                          ],
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );

    overlay.insert(backdropEntry);
    overlay.insert(overlayEntry);
    _setStateSafe(() {
      _openAgentCompensationDropdownIndex = index;
      _currentAgentCompensationBackdropEntry = backdropEntry;
      _currentAgentCompensationDropdownEntry = overlayEntry;
