  Widget _buildLayoutCard(int layoutIndex, Map<String, dynamic> layout) {
    // Convert plots to proper type List<Map<String, dynamic>>
    final plotsData = layout['plots'];
    List<Map<String, dynamic>> plots;
    if (plotsData is List) {
      plots = plotsData.map((p) {
        if (p is Map<String, dynamic>) {
          return p;
        } else if (p is Map) {
          return Map<String, dynamic>.from(p);
        } else {
          return <String, dynamic>{};
        }
      }).toList();
    } else {
      plots = [];
    }

    final layoutNameController = _layoutNameControllers[layoutIndex] ??
        TextEditingController(
            text: layout['name'] ?? 'Layout ${layoutIndex + 1}');
    if (_layoutNameControllers[layoutIndex] == null) {
      _layoutNameControllers[layoutIndex] = layoutNameController;
    }
    final isLayoutNameUndoSelected =
        _isLayoutUndoCellSelected(layoutIndex, 'layoutName');
    final layoutImagePath = (layout['layoutImagePath'] ?? '').toString().trim();
    final layoutImageDocId =
        (layout['layoutImageDocId'] ?? '').toString().trim();
    final hasUploadedLayoutImage =
        layoutImagePath.isNotEmpty || layoutImageDocId.isNotEmpty;
    final layoutImageIconAsset = hasUploadedLayoutImage
        ? 'assets/images/Expense_doc_after_upload.svg'
        : 'assets/images/Expense_doc.svg';

    // Calculate totals for this layout
    double totalArea = 0.0;
    double totalAllInCost = 0.0;
    double totalPlotCost = 0.0;
    // Display-unit rate for the All-in Cost column.
    final allInCost = _allInCostPerDisplayUnit;

    int plotCount = 0;
    for (int i = 0; i < plots.length; i++) {
      final areaKey = '${layoutIndex}_$i';
      final areaController = _plotAreaControllers[areaKey];
      if (areaController != null) {
        final areaDisplay = double.tryParse(
                areaController.text.replaceAll(',', '').replaceAll(' ', '')) ??
            0.0;
        final areaSqft = _plotAreaSqftForKey(areaKey, areaController);
        totalArea += areaDisplay;
        // Only count plots with area > 0
        if (areaSqft > 0) {
          plotCount++;
        }
        // Total Plot Cost uses rounded Area (3dp) * rounded All-in Cost (2dp).
        totalPlotCost +=
            _plotTotalCostFromBaseRoundedFigures(areaKey, areaController);
      }
    }

    // Total All-in Cost = sum of all-in cost values in the column = all-in cost rate * number of plots
    totalAllInCost = allInCost * plotCount;

    return Listener(
      behavior: HitTestBehavior.translucent,
      onPointerDown: (_) {
        _clearLayoutUndoSelection(layoutIndex);
      },
      child: Container(
        padding: const EdgeInsets.all(16),
        clipBehavior: Clip.none,
        decoration: BoxDecoration(
          color: const Color(0xFFF8F9FA),
          borderRadius: BorderRadius.circular(8),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withOpacity(0.25),
              blurRadius: 2,
              offset: const Offset(0, 0),
              spreadRadius: 0,
            ),
          ],
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            // Layout header
            Row(
              children: [
                Text(
                  '${layoutIndex + 1}. Layout: ',
                  style: GoogleFonts.inter(
                    fontSize: 14,
                    fontWeight: FontWeight.w500,
                    color: Colors.black,
                  ),
                ),
                const SizedBox(width: 16),
                _buildFocusAwareInputContainer(
                  focusNode: _layoutNameFocusNodes.putIfAbsent(
                      layoutIndex, () => FocusNode()),
                  backgroundColor: Colors.white,
                  defaultShadowColor:
                      layoutNameController.text.isEmpty ? Colors.red : null,
                  width: 304,
                  child: Stack(
                    children: [
                      TextField(
                        controller: layoutNameController,
                        textAlign: TextAlign.left,
                        textAlignVertical: TextAlignVertical.center,
                        focusNode: _layoutNameFocusNodes.putIfAbsent(
                            layoutIndex, () => FocusNode()),
                        onTap: () {
                          _captureLayoutUndoSnapshot(
                            layoutIndex,
                            selectField: 'layoutName',
                            source: _ExpenseUndoSource.edit,
                          );
                        },
                        onChanged: (value) {
                          if (_preserveLayoutDragUndoUntilDataChange
                              .contains(layoutIndex)) {
                            _preserveLayoutDragUndoUntilDataChange
                                .remove(layoutIndex);
                            _captureLayoutUndoSnapshot(
                              layoutIndex,
                              selectField: 'layoutName',
                              source: _ExpenseUndoSource.edit,
                            );
                          }
                          _layouts[layoutIndex]['name'] = value;
                          setState(() {});
                          _onDataChanged();
                        },
                        decoration: InputDecoration(
                          hintText: '',
                          border: InputBorder.none,
                          contentPadding:
                              const EdgeInsets.symmetric(vertical: 12),
                          isDense: true,
                        ),
                        style: GoogleFonts.inter(
                          fontSize: 14,
                          fontWeight: FontWeight.normal,
                          color: isLayoutNameUndoSelected
                              ? Colors.white
                              : Colors.black,
                          background: isLayoutNameUndoSelected
                              ? (Paint()..color = const Color(0xFF0C8CE9))
                              : null,
                        ),
                      ),
                      if (layoutNameController.text.isEmpty)
                        Positioned.fill(
                          child: IgnorePointer(
                            child: Padding(
                              padding: const EdgeInsets.symmetric(vertical: 6),
                              child: Align(
                                alignment: Alignment.centerLeft,
                                child: Text(
                                  'Enter Layout name or number',
                                  style: GoogleFonts.inter(
                                    fontSize: 14,
                                    fontWeight: FontWeight.normal,
                                    color: Colors.black.withOpacity(0.8),
                                  ),
                                ),
                              ),
                            ),
                          ),
                        ),
                    ],
                  ),
                ),
                const SizedBox(width: 24),
                Container(
                  width: 4,
                  height: 4,
