  void _showCategoryDropdown(BuildContext context, int index, GlobalKey key) {
    final RenderBox? renderBox =
        key.currentContext?.findRenderObject() as RenderBox?;
    if (renderBox == null) return;
    final overlay = Overlay.of(context);
    final overlayBox = overlay.context.findRenderObject() as RenderBox;
    final offset = renderBox.localToGlobal(Offset.zero, ancestor: overlayBox);

    OverlayEntry? backdropEntry;
    OverlayEntry? overlayEntry;
    void closeDropdown() {
      overlayEntry?.remove();
      backdropEntry?.remove();
      if (mounted) {
        setState(() {
          _currentCategoryDropdownEntry = null;
          _currentCategoryBackdropEntry = null;
          _openCategoryDropdownIndex = null;
        });
      } else {
        _currentCategoryDropdownEntry = null;
        _currentCategoryBackdropEntry = null;
        _openCategoryDropdownIndex = null;
      }
    }

    backdropEntry = OverlayEntry(
      builder: (context) => Positioned.fill(
        child: GestureDetector(
          onTap: closeDropdown,
          child: Container(color: Colors.transparent),
        ),
      ),
    );

    const double headerHorizontalPadding = 8;
    const double headerTopPadding = 8;
    const double headerBottomPadding = 8;
    const double listHorizontalPadding = 8;
    const double listTopPadding = 0;
    const double listBottomPadding = 8;
    const double optionHeight = 32;
    const double estimatedHeaderTextHeight = 16;
    const double dropdownOffset = 8;
    const double optionGap = 0;
    const double columnHorizontalInset = 8.0;
    final double topBelow = offset.dy + renderBox.size.height + dropdownOffset;
    final topRight = renderBox.localToGlobal(
      Offset(renderBox.size.width, 0),
      ancestor: overlayBox,
    );
    final double triggerWidth = max(1.0, topRight.dx - offset.dx);
    final double rawDropdownWidth = triggerWidth + (columnHorizontalInset * 2);
    final double maxAllowedWidth = max(1.0, overlayBox.size.width - 16.0);
    final double dropdownWidth = min(rawDropdownWidth, maxAllowedWidth);
    final double unclampedLeft = offset.dx - columnHorizontalInset;
    final double maxLeft =
        max(8.0, overlayBox.size.width - dropdownWidth - 8.0);
    final double left = unclampedLeft.clamp(8.0, maxLeft).toDouble();
    final double popupHeaderFontSize =
        (12.0 * _tableZoomLevel).clamp(10.0, 12.0);
    final int optionCount = _expenseCategories.length;
    final bool showHeader =
        (_expenses[index]['category']?.toString() ?? '').trim().isNotEmpty;
    final double headerHeight = showHeader
        ? (headerTopPadding + estimatedHeaderTextHeight + headerBottomPadding)
        : 0;
    final double calculatedMenuHeight = headerHeight +
        listTopPadding +
        (optionCount * optionHeight) +
        ((optionCount - 1) * optionGap) +
        listBottomPadding;
    final double overlayHeight = overlayBox.size.height;
    final double spaceBelow = overlayHeight - topBelow - dropdownOffset;
    final double spaceAbove = offset.dy - dropdownOffset;
    final bool shouldOpenUpward =
        calculatedMenuHeight > spaceBelow && spaceAbove > spaceBelow;
    final double availableHeight =
        shouldOpenUpward ? max(0, spaceAbove) : max(0, spaceBelow);
    final double maxMenuHeight = min(calculatedMenuHeight, availableHeight);
    final double top = shouldOpenUpward
        ? max(dropdownOffset, offset.dy - dropdownOffset - maxMenuHeight)
        : topBelow;

    overlayEntry = OverlayEntry(
      builder: (context) => Positioned(
        left: left,
        top: top,
        child: Material(
          color: Colors.transparent,
          child: Container(
            width: dropdownWidth,
            height: maxMenuHeight,
            decoration: BoxDecoration(
              color: const Color(0xFFF8F9FA),
              borderRadius: BorderRadius.circular(8),
              boxShadow: [
                BoxShadow(
                  color: Colors.black.withOpacity(0.5),
                  blurRadius: 2,
                  offset: const Offset(0, 0),
                  spreadRadius: 0,
                ),
              ],
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                if (showHeader)
                  Padding(
                    padding: const EdgeInsets.fromLTRB(
                      headerHorizontalPadding,
                      headerTopPadding,
                      headerHorizontalPadding,
                      headerBottomPadding,
                    ),
                    child: Text(
                      'Select Category',
                      style: GoogleFonts.inter(
                        fontSize: popupHeaderFontSize,
                        fontWeight: FontWeight.normal,
                        color: Colors.black,
                      ),
                    ),
                  ),
                Expanded(
                  child: ScrollConfiguration(
                    behavior: const MaterialScrollBehavior()
                        .copyWith(scrollbars: false),
                    child: ListView.separated(
                      padding: const EdgeInsets.fromLTRB(
                        listHorizontalPadding,
                        listTopPadding,
                        listHorizontalPadding,
                        listBottomPadding,
                      ),
                      itemCount: _expenseCategories.length,
                      separatorBuilder: (_, __) =>
                          const SizedBox(height: optionGap),
                      itemBuilder: (context, itemIndex) {
                        final category = _expenseCategories[itemIndex];
                        final categoryColor = _getCategoryColor(category);
                        return GestureDetector(
                          onTap: () {
                            closeDropdown();
                            _captureExpenseUndoSnapshot(
                              selectIndex: index,
                              selectField: 'item',
                              source: _ExpenseUndoSource.category,
                            );
                            setState(() {
                              _expenses[index]['category'] = category;
                            });
                            _onDataChanged();
                          },
                          child: SizedBox(
                            height: optionHeight,
                            child: Container(
                              color: Colors.transparent,
                              alignment: Alignment.centerLeft,
                              child: _buildExpenseCategoryChip(
                                label: category,
                                color: categoryColor,
                                fontSize: 11,
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 8,
                                  vertical: 3,
                                ),
                                borderRadius: 6,
                              ),
                            ),
                          ),
                        );
                      },
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
      ),
    );

    overlay.insert(backdropEntry);
    overlay.insert(overlayEntry);

    // Store references to the open dropdown
    if (mounted) {
      setState(() {
        _currentCategoryBackdropEntry = backdropEntry;
        _currentCategoryDropdownEntry = overlayEntry;
        _openCategoryDropdownIndex = index;
      });
    } else {
      _currentCategoryBackdropEntry = backdropEntry;
      _currentCategoryDropdownEntry = overlayEntry;
      _openCategoryDropdownIndex = index;
    }
  }

  void _showLayoutMenu(BuildContext context, int layoutIndex, String layoutName,
      GlobalKey anchorKey) {
    final RenderBox? renderBox =
        anchorKey.currentContext?.findRenderObject() as RenderBox?;
    if (renderBox == null) return;

    final overlay = Overlay.of(context);
    final overlayBox = overlay.context.findRenderObject() as RenderBox;
    final offset = renderBox.localToGlobal(Offset.zero, ancestor: overlayBox);

    OverlayEntry? backdropEntry;
    OverlayEntry? overlayEntry;

    // Function to close menu
    void closeMenu() {
      overlayEntry?.remove();
      backdropEntry?.remove();
      _openLayoutMenuIndex = null;
      _currentLayoutMenuEntry = null;
      _currentLayoutMenuBackdropEntry = null;
    }

    // Create backdrop
    backdropEntry = OverlayEntry(
      builder: (context) => Positioned.fill(
        child: GestureDetector(
          onTap: closeMenu,
          child: Container(color: Colors.transparent),
        ),
      ),
    );

    // Calculate menu position (below and aligned to right of three dots button)
    final menuWidth = 165.0;
    final leftPosition = offset.dx + renderBox.size.width - menuWidth - 12;
    final topPosition = offset.dy + renderBox.size.height + 8;

    // Create menu
    overlayEntry = OverlayEntry(
      builder: (context) => Positioned(
        left: leftPosition,
        top: topPosition,
        child: Material(
          color: Colors.transparent,
          child: Container(
            width: menuWidth,
            height: 52,
            padding: const EdgeInsets.all(8),
            decoration: BoxDecoration(
              color: const Color(0xFFF8F9FA),
              borderRadius: BorderRadius.circular(8),
              boxShadow: [
                BoxShadow(
                  color: Colors.black.withOpacity(0.5),
                  blurRadius: 2,
                  offset: const Offset(0, 0),
                  spreadRadius: 0,
                ),
              ],
            ),
            child: GestureDetector(
              onTap: () {
                closeMenu();
                _showDeleteLayoutDialog(context, layoutIndex, layoutName);
              },
              child: Container(
                width: double.infinity,
                height: double.infinity,
                padding:
                    const EdgeInsets.symmetric(horizontal: 16, vertical: 4),
                decoration: BoxDecoration(
                  color: Colors.white,
                  borderRadius: BorderRadius.circular(8),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.25),
                      blurRadius: 2,
                      offset: const Offset(0, 0),
                      spreadRadius: 0,
                    ),
                  ],
                ),
                child: Center(
                  child: Text(
                    'Delete layout',
                    style: GoogleFonts.inter(
                      fontSize: 14,
                      fontWeight: FontWeight.normal,
                      color: Colors.red,
                    ),
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );

    overlay.insert(backdropEntry);
    overlay.insert(overlayEntry);

    _currentLayoutMenuEntry = overlayEntry;
    _currentLayoutMenuBackdropEntry = backdropEntry;
    _openLayoutMenuIndex = layoutIndex;
  }

  void _showDeleteLayoutDialog(
      BuildContext context, int layoutIndex, String layoutName) {
    showDialog(
      context: context,
      barrierColor: Colors.black.withOpacity(0.5),
      barrierDismissible: true,
      builder: (context) => Dialog(
        backgroundColor: Colors.transparent,
        insetPadding:
            const EdgeInsets.only(left: 24, right: 24, top: 8, bottom: 100),
        alignment: Alignment.topCenter,
        child: BackdropFilter(
          filter: ImageFilter.blur(sigmaX: 4, sigmaY: 4),
          child: Container(
            width: 538,
            padding: const EdgeInsets.all(16),
            decoration: BoxDecoration(
              color: const Color(0xFFF8F9FA),
              borderRadius: BorderRadius.circular(8),
              boxShadow: [
                BoxShadow(
                  color: Colors.black.withOpacity(0.25),
                  blurRadius: 2,
                  offset: const Offset(0, 0),
                  spreadRadius: 0,
                ),
              ],
            ),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                // Header with title and close button
                Row(
                  mainAxisAlignment: MainAxisAlignment.spaceBetween,
                  children: [
                    Text(
                      'Delete Layout?',
                      style: GoogleFonts.inter(
                        fontSize: 20,
                        fontWeight: FontWeight.w600,
                        color: Colors.black,
                      ),
                    ),
                    GestureDetector(
                      onTap: () => Navigator.of(context).pop(),
                      child: Container(
                        width: 22.627,
                        height: 22.627,
                        alignment: Alignment.center,
                        child: Icon(
                          Icons.close,
                          size: 16,
                          color: const Color(0xFF0C8CE9),
                        ),
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 16),
                // Layout name
                Text(
                  '${layoutIndex + 1}. Layout: ${layoutName.isEmpty ? 'NA' : layoutName}',
                  style: GoogleFonts.inter(
                    fontSize: 14,
                    fontWeight: FontWeight.normal,
                    color: Colors.black.withOpacity(0.8),
                  ),
                ),
                const SizedBox(height: 8),
                // Warning messages
                Text(
                  'This will permanently delete this layout and all plots inside it, including their area, cost, and partner assignments.',
                  style: GoogleFonts.inter(
                    fontSize: 14,
                    fontWeight: FontWeight.normal,
                    color: Colors.black.withOpacity(0.8),
                  ),
                ),
                const SizedBox(height: 8),
                Text(
                  'This action cannot be undone.',
                  style: GoogleFonts.inter(
                    fontSize: 14,
                    fontWeight: FontWeight.normal,
                    color: Colors.black.withOpacity(0.8),
                  ),
                ),
                const SizedBox(height: 16),
                // Buttons
                Row(
                  mainAxisAlignment: MainAxisAlignment.spaceBetween,
                  children: [
                    GestureDetector(
                      onTap: () => Navigator.of(context).pop(),
                      child: Container(
                        height: 44,
                        padding: const EdgeInsets.symmetric(
                            horizontal: 16, vertical: 4),
                        decoration: BoxDecoration(
                          color: Colors.white,
                          borderRadius: BorderRadius.circular(8),
                          boxShadow: [
                            BoxShadow(
                              color: Colors.black.withOpacity(0.25),
                              blurRadius: 2,
                              offset: const Offset(0, 0),
                              spreadRadius: 0,
                            ),
                          ],
                        ),
                        child: Center(
                          child: Text(
                            'Cancel',
                            style: GoogleFonts.inter(
                              fontSize: 14,
                              fontWeight: FontWeight.normal,
                              color: const Color(0xFF0C8CE9),
                            ),
                          ),
                        ),
                      ),
                    ),
                    GestureDetector(
                      onTap: () async {
                        Navigator.of(context).pop();
                        // Delete the layout
                        if (layoutIndex < _layouts.length) {
                          final layout = _layouts[layoutIndex];
                          final layoutNameController =
                              _layoutNameControllers[layoutIndex];
                          final layoutNameToDelete =
                              layoutNameController?.text.trim() ??
                                  layout['name']?.toString().trim() ??
                                  '';

                          // Delete from database if layout has a name and project ID
                          if (layoutNameToDelete.isNotEmpty &&
                              widget.projectId != null) {
                            try {
                              // Find layout by name
                              final existingLayouts = await _supabase
                                  .from('layouts')
                                  .select('id')
                                  .eq('project_id', widget.projectId!)
                                  .eq('name', layoutNameToDelete)
                                  .maybeSingle();

                              if (existingLayouts != null &&
                                  existingLayouts['id'] != null) {
                                final layoutId =
                                    existingLayouts['id'] as String;

                                // Delete all plots in this layout first
                                await _supabase
                                    .from('plots')
                                    .delete()
                                    .eq('layout_id', layoutId);

                                // Delete the layout
                                await _supabase
                                    .from('layouts')
                                    .delete()
                                    .eq('id', layoutId);
                              }
                            } catch (e) {
                              print('Error deleting layout from database: $e');
                            }
                          }

                          // Remove from local state
                          setState(() {
                            // Dispose the controller and focus node for the deleted layout
                            _layoutNameControllers[layoutIndex]?.dispose();
                            _layoutNameFocusNodes[layoutIndex]?.dispose();

                            _layouts.removeAt(layoutIndex);

                            // Reindex remaining layouts - move controllers and focus nodes down
                            final controllersToMove =
                                <int, TextEditingController>{};
                            final focusNodesToMove = <int, FocusNode>{};

                            // Collect controllers and focus nodes that need to be moved
                            for (int i = layoutIndex + 1;
                                i < _layouts.length + 1;
                                i++) {
                              if (_layoutNameControllers.containsKey(i)) {
                                controllersToMove[i] =
                                    _layoutNameControllers[i]!;
                              }
                              if (_layoutNameFocusNodes.containsKey(i)) {
                                focusNodesToMove[i] = _layoutNameFocusNodes[i]!;
                              }
                            }

                            // Remove the deleted layout's controllers
                            _layoutNameControllers.remove(layoutIndex);
                            _layoutNameFocusNodes.remove(layoutIndex);

                            // Remove old entries for layouts that need to be reindexed
                            for (int i = layoutIndex + 1;
                                i < _layouts.length + 1;
                                i++) {
                              _layoutNameControllers.remove(i);
                              _layoutNameFocusNodes.remove(i);
                            }

                            // Add back with new indices (shifted down by 1)
                            for (var entry in controllersToMove.entries) {
                              _layoutNameControllers[entry.key - 1] =
                                  entry.value;
                            }
                            for (var entry in focusNodesToMove.entries) {
                              _layoutNameFocusNodes[entry.key - 1] =
                                  entry.value;
                            }
                          });
                          _onDataChanged();
                        }
                      },
                      child: Container(
                        height: 44,
                        padding: const EdgeInsets.symmetric(
                            horizontal: 16, vertical: 4),
                        decoration: BoxDecoration(
                          color: Colors.white,
                          borderRadius: BorderRadius.circular(8),
                          boxShadow: [
                            BoxShadow(
                              color: Colors.black.withOpacity(0.25),
                              blurRadius: 2,
                              offset: const Offset(0, 0),
                              spreadRadius: 0,
                            ),
                          ],
                        ),
                        child: Row(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            Text(
                              'Delete Layout',
                              style: GoogleFonts.inter(
                                fontSize: 14,
                                fontWeight: FontWeight.normal,
                                color: Colors.red,
                              ),
                            ),
                            const SizedBox(width: 8),
                            SvgPicture.asset(
                              'assets/images/Delete_layout.svg',
                              width: 13,
                              height: 16,
                              fit: BoxFit.contain,
                              placeholderBuilder: (context) => const SizedBox(
                                width: 13,
                                height: 16,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

