                                    // Delete all plots first
                                    for (var layout in existingLayouts) {
                                      final layoutId = layout['id'] as String;
                                      await _supabase
                                          .from('plots')
                                          .delete()
                                          .eq('layout_id', layoutId);
                                    }

                                    // Delete all layouts
                                    await _supabase
                                        .from('layouts')
                                        .delete()
                                        .eq('project_id', widget.projectId!);
                                  } catch (e) {
                                    print(
                                        'Error deleting all layouts from database: $e');
                                  }
                                }

                                // Clear local state
                                setState(() {
                                  _layouts.clear();
                                  _layoutNameControllers.clear();
                                  _layoutNameFocusNodes.clear();
                                  _numberOfLayoutsController.text = '0';
                                  _isCreateTableEnabled = false;
                                });
                                _onDataChanged();
                              }
                            : null,
                        child: Opacity(
                          opacity:
                              confirmController.text.toLowerCase().trim() ==
                                      'delete'
                                  ? 1.0
                                  : 0.5,
                          child: Container(
                            height: 44,
                            padding: const EdgeInsets.symmetric(
                                horizontal: 16, vertical: 4),
                            decoration: BoxDecoration(
                              color: const Color(0xFFF8F9FA),
                              borderRadius: BorderRadius.circular(8),
                              boxShadow: [
                                BoxShadow(
                                  color: Colors.black.withOpacity(0.5),
                                  blurRadius: 2,
                                  offset: const Offset(0, 0),
                                  spreadRadius: 0,
                                ),
                              ],
                            ),
                            child: Center(
                              child: Row(
                                mainAxisSize: MainAxisSize.min,
                                crossAxisAlignment: CrossAxisAlignment.center,
                                children: [
                                  Text(
                                    'Delete all layouts',
                                    style: GoogleFonts.inter(
                                      fontSize: 14,
                                      fontWeight: FontWeight.normal,
                                      height: 1.0,
                                      color: confirmController.text
                                                  .toLowerCase()
                                                  .trim() ==
                                              'delete'
                                          ? Colors.red
                                          : Colors.red.withOpacity(0.5),
                                    ),
                                  ),
                                  const SizedBox(width: 8),
                                  SvgPicture.asset(
                                    'assets/images/Delete_layout.svg',
                                    width: 13,
                                    height: 16,
                                    fit: BoxFit.contain,
                                    colorFilter: ColorFilter.mode(
                                      confirmController.text
                                                  .toLowerCase()
                                                  .trim() ==
                                              'delete'
                                          ? Colors.red
                                          : Colors.red.withOpacity(0.5),
                                      BlendMode.srcIn,
                                    ),
                                  ),
                                ],
                              ),
                            ),
                          ),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }
}

class _LayoutViewerStroke {
  final List<Offset> normalizedPoints;
  final Color color;
  final double thickness;

  _LayoutViewerStroke({
    required this.normalizedPoints,
    required this.color,
    required this.thickness,
  });
}

class _LayoutViewerStrokesPainter extends CustomPainter {
  final List<_LayoutViewerStroke> strokes;

  const _LayoutViewerStrokesPainter({
    required this.strokes,
    Listenable? repaint,
  }) : super(repaint: repaint);

  @override
  void paint(Canvas canvas, Size size) {
    for (final stroke in strokes) {
      if (stroke.normalizedPoints.isEmpty) continue;

      final strokePaint = Paint()
        ..color = stroke.color
        ..style = PaintingStyle.stroke
        ..strokeWidth = max(1.0, stroke.thickness * 2)
        ..strokeCap = StrokeCap.round
        ..strokeJoin = StrokeJoin.round;

      Offset denormalize(Offset point) => Offset(
            point.dx * size.width,
            point.dy * size.height,
          );

      if (stroke.normalizedPoints.length == 1) {
        final center = denormalize(stroke.normalizedPoints.first);
        final dotPaint = Paint()
          ..color = stroke.color
          ..style = PaintingStyle.fill;
        canvas.drawCircle(center, strokePaint.strokeWidth / 2, dotPaint);
        continue;
      }

      final path = Path()
        ..moveTo(
          stroke.normalizedPoints.first.dx * size.width,
          stroke.normalizedPoints.first.dy * size.height,
        );
      for (int i = 1; i < stroke.normalizedPoints.length; i++) {
        final point = denormalize(stroke.normalizedPoints[i]);
        path.lineTo(point.dx, point.dy);
      }
      canvas.drawPath(path, strokePaint);
    }
  }

  @override
  bool shouldRepaint(covariant _LayoutViewerStrokesPainter oldDelegate) {
    return true;
  }
}

// Custom widget for focus-aware input containers
class _FocusAwareInputContainer extends StatefulWidget {
  final FocusNode focusNode;
  final Widget child;
  final VoidCallback? onFocusLost;
  final double width;
  final double height;
  final Color backgroundColor;
  final double borderRadius;
  final Color? defaultShadowColor;

  const _FocusAwareInputContainer({
    required this.focusNode,
    required this.child,
    this.onFocusLost,
    this.width = double.infinity,
    this.height = 40,
    this.backgroundColor = const Color(0xFFF8F9FA),
    this.borderRadius = 8,
    this.defaultShadowColor,
  });

  @override
  State<_FocusAwareInputContainer> createState() =>
      _FocusAwareInputContainerState();
}

class _FocusAwareInputContainerState extends State<_FocusAwareInputContainer> {
  late VoidCallback _focusListener;
  bool _hadFocus = false;

  @override
  void initState() {
    super.initState();
    _hadFocus = widget.focusNode.hasFocus;
    _focusListener = () {
      // Call onFocusLost when focus changes from true to false
      if (_hadFocus &&
          !widget.focusNode.hasFocus &&
          widget.onFocusLost != null) {
        widget.onFocusLost!();
      }
      _hadFocus = widget.focusNode.hasFocus;
      setState(() {});
    };
    widget.focusNode.addListener(_focusListener);
  }

  @override
  void dispose() {
    widget.focusNode.removeListener(_focusListener);
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      width: widget.width,
      height: widget.height,
      padding: const EdgeInsets.symmetric(horizontal: 8),
      decoration: BoxDecoration(
        color: widget.backgroundColor,
        borderRadius: BorderRadius.circular(widget.borderRadius),
        boxShadow: [
          BoxShadow(
            color: widget.focusNode.hasFocus
                ? const Color(0xFF0C8CE9) // Focus color: #0C8CE9 (solid blue)
                : (widget.defaultShadowColor ??
                    Colors.black.withOpacity(0.15)), // Default color
            blurRadius: 2,
            offset: const Offset(0, 0),
            spreadRadius: 0,
          ),
        ],
      ),
      child: widget.child,
    );
  }
}
